from dataclasses import dataclass, field
from typing import List, Optional


@dataclass
class OptionDependency:
    name: str
    locked_in_months: int   # How many months this dependency locks the decision
    can_wrap: bool          # Can we add an abstraction layer around it?


@dataclass
class ArchitectureOption:
    option_id: str
    title: str
    reversibility_score: float          # composite from ReversibilityScorecard
    reversibility_tier: str             # TRIVIAL / LOW / MODERATE / HIGH / IMPRACTICAL
    time_to_first_value_days: int       # How quickly can we validate this path?
    dependencies: List[OptionDependency] = field(default_factory=list)
    risks: List[str] = field(default_factory=list)
    expires_if: Optional[str] = None    # Condition that makes this option void

    def lock_in_horizon_months(self) -> int:
        """Longest lock-in across all dependencies."""
        if not self.dependencies:
            return 0
        return max(d.locked_in_months for d in self.dependencies)

    def all_deps_wrappable(self) -> bool:
        return all(d.can_wrap for d in self.dependencies)

    def option_brief(self) -> str:
        lock = self.lock_in_horizon_months()
        wrap = "wrappable" if self.all_deps_wrappable() else "hard dependency"
        return (
            f"[{self.option_id}] {self.title}\n"
            f"  Reversibility: {self.reversibility_tier} (score {self.reversibility_score})\n"
            f"  Lock-in horizon: {lock} months ({wrap})\n"
            f"  Time to first value: {self.time_to_first_value_days}d\n"
            f"  Expires if: {self.expires_if or 'N/A'}"
        )


@dataclass
class OptionsAnalysis:
    decision_title: str
    options: List[ArchitectureOption]
    recommended_option_id: Optional[str] = None
    recommendation_rationale: str = ""

    def most_reversible(self) -> ArchitectureOption:
        return min(self.options, key=lambda o: o.reversibility_score)

    def fastest_validation(self) -> ArchitectureOption:
        return min(self.options, key=lambda o: o.time_to_first_value_days)

    def recommendation_summary(self) -> str:
        rec = next((o for o in self.options if o.option_id == self.recommended_option_id), None)
        if not rec:
            return "No recommendation set."
        mr = self.most_reversible()
        premium = rec.reversibility_score - mr.reversibility_score
        return (
            f"Recommended: {rec.title}\n"
            f"Reversibility premium over safest option: {premium:.2f} points\n"
            f"Rationale: {self.recommendation_rationale}"
        )
